grades_input = input().split()
grades = []
for x in grades_input:
    grades.append(int(x))

Q = int(input())

for _ in range(Q):
    operation = input().split()
    if operation[0] == "add":
        grade = int(operation[1])
        grades.append(grade)
    elif operation[0] == "insert":
        index = int(operation[1])
        grade = int(operation[2])
        if index <= len(grades):
            grades.insert(index, grade)
    elif operation[0] == "remove":
        grade = int(operation[1])
        if grade in grades:
            grades.remove(grade)
    elif operation[0] == "find":
        if grades:
            print(max(grades))
        else:
            print("No grades available")

for i in range(len(grades)):
    if i < len(grades) - 1:
        print(grades[i], end=' ')
    else:
        print(grades[i])
